import React from 'react'
import { trackLink } from '@fs/zion-analytics'
import { css } from '@linaria/core'
import { colors, Image } from '@fs/zion-ui'
import { type ThumbnailProps } from '../../types/LazyBrightcovePlayer'
import playButton from './assets/play-button.svg'

const containerCss = css`
  position: relative;
`

const buttonCss = css`
  --image-size: 100px;

  border: none;
  padding: 0;
  position: absolute;
  top: calc(50% - var(--image-size) / 2);
  inset-inline-start: calc(50% - var(--image-size) / 2);
  background: none;
  transition: transform 150ms ease-in-out;

  &:focus {
    outline: 2px solid ${colors.blue60};
  }
  &:hover {
    transform: scale(1.06);
  }
`

export const ThumbnailButton = ({ onClick, title, thumbnail, aspectRatio }: ThumbnailProps): JSX.Element => {
  const onButtonClick = (): void => {
    trackLink({ name: 'Video Placeholder' })
    onClick?.(true)
  }

  return (
    <div className={containerCss}>
      <Image src={thumbnail} alt="" style={{ aspectRatio }} />
      <button
        type="button"
        onClick={onButtonClick}
        onKeyUp={({ key }) => {
          if (key === 'Enter') {
            onButtonClick()
          }
        }}
        className={buttonCss}
        aria-label={title}
        title={title}
      >
        <Image src={playButton} alt="" />
      </button>
    </div>
  )
}
