/**
 * Taken from ZionCMS Video Component
 */
import React from 'react'
import { LazyBrightcovePlayer } from '@fs/zion-video'
import { trackLink } from '@fs/zion-analytics'

const BrightcovePlayerWrapper = React.lazy(() => import('./BrightcovePlayerWrapper'))

declare type VideoProps = {
  autoplay?: boolean
  thumbnailUrl?: string
  title?: string
  videoProvider?: {
    __typename?: string
    accountId?: string
    videoId?: string
  }
}

/**
 * Renders Brightcove videos for RootsTech promo with support for both autoplay
 * and lazy-loaded player configurations. Uses BrightcovePlayerWrapper for autoplay
 * videos and LazyBrightcovePlayer for non-autoplay videos with thumbnail support.
 *
 * @param {VideoProps} props - Video configuration properties
 * @param {boolean} [props.autoplay] - Whether the video should autoplay (with mute)
 * @param {string} [props.title] - Video title for accessibility
 * @param {string} [props.thumbnailUrl=''] - URL of the video thumbnail image
 * @param {object} [props.videoProvider] - Brightcove video provider configuration
 * @param {string} [props.videoProvider.__typename] - Provider type, must be 'RootsTechBrightcoveVideoProvider'
 * @param {string} [props.videoProvider.accountId] - Brightcove account ID
 * @param {string} [props.videoProvider.videoId] - Brightcove video ID
 * @returns {JSX.Element} Video player element or error message
 */
export default function Video({ videoProvider, thumbnailUrl = '', title, autoplay }: VideoProps): JSX.Element {
  let videoChild

  const truncatedTitle = title?.slice(0, 20)
  const onMute = (): void => {
    if (!truncatedTitle) return
    trackLink({ name: `Promo:${truncatedTitle}:Muted` })
  }
  const onUnmute = (): void => {
    if (!truncatedTitle) return
    trackLink({ name: `Promo:${truncatedTitle}:Unmuted` })
  }

  // eslint-disable-next-line no-underscore-dangle
  if (videoProvider?.__typename === 'RootsTechBrightcoveVideoProvider') {
    if (autoplay) {
      videoChild = (
        <BrightcovePlayerWrapper
          title={title}
          accountId={videoProvider?.accountId || ''}
          videoId={videoProvider?.videoId || ''}
          autoplay
          muted
          onMute={onMute}
          onUnmute={onUnmute}
        />
      )
    } else {
      videoChild = (
        <LazyBrightcovePlayer
          title={title}
          accountId={videoProvider?.accountId || ''}
          videoId={videoProvider?.videoId || ''}
          thumbnail={thumbnailUrl}
          onMute={onMute}
          onUnmute={onUnmute}
        />
      )
    }
  } else {
    videoChild = (
      <div>
        ERROR: Video type not supported
        {/* eslint-disable-next-line no-underscore-dangle */}
        {videoProvider?.__typename ? ` (type: ${videoProvider.__typename})` : ''}
      </div>
    )
  }

  return <div data-testid="zion-cms-video">{videoChild}</div>
}
