import React, { useState, lazy, Suspense, useMemo } from 'react'
import ErrorBoundary from '@fs/zion-error-boundary'
import { useTranslation } from 'react-i18next'
import type { LazyBrightcovePlayerProps } from '../../types/LazyBrightcovePlayer'
import { ThumbnailButton } from './ThumbnailButton'

const BrightcovePlayer = lazy(() => import('./BrightcovePlayer'))

export const LazyBrightcovePlayer = ({
  title: titleProp,
  thumbnail,
  aspectRatio = '16 / 9',

  ...props
}: LazyBrightcovePlayerProps): JSX.Element => {
  const [shouldLoad, setLoad] = useState(false)
  const [t] = useTranslation()

  useMemo(() => {
    if (!thumbnail) {
      console.error('LazyBrightcovePlayer: thumbnail is required')
    }
  }, [thumbnail])

  const title = titleProp || t('video.thumbnail.title', 'Click here to play the video')

  const playerProps = {
    title,
    aspectRatio,
    ...props,
  }

  return (
    <Suspense fallback={<ThumbnailButton title={title} thumbnail={thumbnail} aspectRatio={aspectRatio} />}>
      <ErrorBoundary>
        {shouldLoad ? (
          <BrightcovePlayer autoplay {...playerProps} />
        ) : (
          <ThumbnailButton onClick={setLoad} title={title} thumbnail={thumbnail} aspectRatio={aspectRatio} />
        )}
      </ErrorBoundary>
    </Suspense>
  )
}
